import api from './api';

export const ExecutionService = {
  // Executions
  createExecution: (workflowId, data, triggeredBy) => 
    api.post(`/workflows/${workflowId}/execute`, data, { params: { triggered_by: triggeredBy } }),
  
  executeWorkflow: (executionId) => 
    api.post(`/executions/${executionId}/run`),
  
  getExecution: (id) => api.get(`/executions/${id}`),
  
  getExecutions: (workflowId) => 
    api.get('/executions', { params: { workflow_id: workflowId } }),
  
  cancelExecution: (id) => api.post(`/executions/${id}/cancel`),
  
  retryExecution: (id) => api.post(`/executions/${id}/retry`)
};

export default ExecutionService;
